1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	export function processScenario(input: any): unknown {
11	  const items = input.steps[0].items;
12	  if (items.length === 0) {
13	    return { results: [{ premium: PROCESSING_FEE }] };
14	  }
15	  const basePremium = BASE_PREMIUM_BY_TYPE[items[0].type];
16	  const premium = basePremium + basePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE;
17	  return { results: [{ premium }] };
18	}
